code.C:
#include <stdio.h>

int main() {
    int T, X;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &X);
        int ans = (500 + X - 1) / X; // ceiling of 500/X
        printf("%d\n", ans);
    }
    return 0;
}

